                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          "w-full py-4 rounded-lg font-bold text-sm uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all duration-300",
